document.addEventListener('DOMContentLoaded',()=>{const enlaces=document.querySelectorAll('a[data-ajax]');enlaces.forEach(enlace=>{enlace.addEventListener('click',async(event)=>{event.preventDefault();const url=enlace.getAttribute('href');const contenido=document.getElementById('contenido');try{const response=await axios.get(url);contenido.innerHTML=response.data;const scripts=contenido.querySelectorAll('script');scripts.forEach(script=>{const newScript=document.createElement('script');newScript.textContent=script.textContent;document.body.appendChild(newScript);document.body.removeChild(newScript);});}catch(error){console.error('Error al cargar el contenido:',error);alert('Hubo un problema al cargar el contenido.');}});});});